        { enunciado: 'A imagem de objetos antigos preservados enquanto a padaria fechou funciona como qual ideia?', alternativas: ['A ideia de que ninguém limpa nem cuida daquele beco há muitos anos, o que não se confirma ao ler com atenção', 'A noção de que objetos simples duram bem mais do que padarias', 'A esperança de que a antiga padaria do bairro vá reabrir um dia', 'O tempo apaga lugares, mas alguns símbolos permanecem como guardiões da memória'], correta: 3 },
        { enunciado: 'Qual é o tema central do texto?', alternativas: ['A relação entre a origem humilde e aquilo que dá sentido à carreira', 'As várias maneiras que as crianças encontram para se divertir', 'A importância de ter dinheiro e ser rico para poder jogar futebol, segundo uma leitura apressada da história', 'O perigo de crianças ficarem jogando bola em becos apertados'], correta: 0 }
